297	char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
298	    double best_overall_eval = std::numeric_limits<double>::lowest();
299	    int best_dir_idx = 0;
300	
301	    int turn_T = current_gs_after_placement.turn_num_1_indexed;
302	
303	    LookaheadConfig config;
304	    if (turn_T <= 12) {
305	        // Early game: depth 3 with fast eval at leaf
306	        config.max_depth = 3;
307	        config.samples[0] = 8;
308	        config.samples[1] = 4;
309	        config.samples[2] = 3;
310	        config.use_fast_at_leaf = true;
311	    } else {
312	        // Rest of game: depth 2 with full eval
313	        config.max_depth = 2;
314	        config.samples[0] = 18;
315	        config.samples[1] = 5;
316	        config.samples[2] = 0;
317	        config.use_fast_at_leaf = false;
318	    }
