char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
    int turn_T = current_gs_after_placement.turn_num_1_indexed;

    // Time budget: total 1800ms across 100 turns, budget proportional to early importance
    // Turns 1-12 get more time per turn, turns 13-100 get less
    double total_elapsed = elapsed_ms();
    double time_remaining = 1800.0 - total_elapsed;
    int turns_remaining = NUM_TURNS - turn_T + 1;

    // Early turns get 2x weight
    double weight = (turn_T <= 20) ? 2.0 : 1.0;
    double total_future_weight = 0.0;
    for (int t = turn_T; t <= NUM_TURNS; ++t) {
        total_future_weight += (t <= 20) ? 2.0 : 1.0;
    }
    double this_turn_budget_ms = time_remaining * weight / total_future_weight;

    // Determine configuration based on available time
    // Iterative deepening: try depth 2 first, then depth 3 if time allows
    LookaheadConfig config2;
    config2.max_depth = 2;
    config2.samples[0] = 18;
    config2.samples[1] = 5;
    config2.samples[2] = 0;
    config2.use_fast_at_leaf = false;

    LookaheadConfig config3;
    config3.max_depth = 3;
    config3.samples[0] = 8;
    config3.samples[1] = 4;
    config3.samples[2] = 3;
    config3.use_fast_at_leaf = true;

    // Always run depth-2 as baseline
    std::array<double, NUM_DIRECTIONS> depth2_evals;
    double best_d2_eval = std::numeric_limits<double>::lowest();
    int best_d2_dir = 0;

    double start_turn = elapsed_ms();

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);
        depth2_evals[i] = eval_lookahead(gs_after_tilt, turn_T, config2.max_depth, config2);
        if (depth2_evals[i] > best_d2_eval) {
            best_d2_eval = depth2_evals[i];
            best_d2_dir = i;
        }
    }

    double d2_time = elapsed_ms() - start_turn;

    // If we have time for depth-3 and it's early enough that depth-3 is beneficial
    if (turn_T <= 30 && d2_time < this_turn_budget_ms * 0.4) {
        // Try depth-3 with remaining time
        double best_d3_eval = std::numeric_limits<double>::lowest();
        int best_d3_dir = 0;
        bool d3_complete = true;

        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
            if (elapsed_ms() - start_turn > this_turn_budget_ms * 0.95) {
                d3_complete = false;
                break;
            }
            GameState gs_after_tilt = current_gs_after_placement;
            gs_after_tilt.apply_tilt(i);
            double eval = eval_lookahead(gs_after_tilt, turn_T, config3.max_depth, config3);
            if (eval > best_d3_eval) {
                best_d3_eval = eval;
                best_d3_dir = i;
            }
        }

        if (d3_complete) {
            return DIR_CHARS[best_d3_dir];
        }
    }

    return DIR_CHARS[best_d2_dir];
}


double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining, const LookaheadConfig& config) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count_param_idx = config.max_depth - depth_remaining;
    int sample_count_this_depth = config.samples[sample_count_param_idx];
    int actual_num_samples = std::min(sample_count_this_depth, num_empty);

    if (actual_num_samples == 0) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val;
        if (actual_num_samples == num_empty) {
            p_val = s + 1;
        } else {
            p_val = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval = std::numeric_limits<double>::lowest();
        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
            GameState S_after_tilt = S_after_placement;
            S_after_tilt.apply_tilt(dir_idx);
            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1, config);
            if (val > max_eval) {
                max_eval = val;
            }
        }
        sum_over_sampled_placements += max_eval;
    }

    return sum_over_sampled_placements / actual_num_samples;
}


